// This function attempts to keep backwards compatibility with old colors

import warning from '@andes/common/build/utils/warning';
import { DEPRECATED_PROGRESS_CIRCULAR_COLORS } from '../constants';
import { WARNING_COLORS } from '../constants/warnings';

/** @typedef {import('../..').ProgressIndicatorCircularProps['color']} ProgressCircularColors */

/**
 * @typedef {Object} Props
 * @prop {ProgressCircularColors} [color]
 */

/** @type {(props:Props) => ProgressCircularColors} */
const computeColorProps = ({ color }) => {
  // @deprecate [color] options: ['blue', 'white'] - Warning from: 9.0.0
  if (typeof color === 'string') {
    warning(!DEPRECATED_PROGRESS_CIRCULAR_COLORS.includes(color), WARNING_COLORS);
  }

  switch (color) {
    case 'blue':
      return 'basic';
    case 'white':
      return 'inverse';
    default:
      return color || 'basic';
  }
};

export default computeColorProps;
